import 'package:flutter/material.dart';
import 'package:local_auth/local_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';

class BiometricAuth {
  static final LocalAuthentication _auth = LocalAuthentication();
  static const String _authKey = 'isAuthenticated';

  static Future<bool> authenticate() async {
    try {
      final bool canAuthenticate = await _auth.canCheckBiometrics;
      final List<BiometricType> availableBiometrics = await _auth.getAvailableBiometrics();
      
      if (!canAuthenticate || availableBiometrics.isEmpty) {
        return false;
      }

      final bool authenticated = await _auth.authenticate(
        localizedReason: 'Please authenticate to access the app',
        options: const AuthenticationOptions(
          stickyAuth: true,
          biometricOnly: true,
        ),
      );

      if (authenticated) {
        final prefs = await SharedPreferences.getInstance();
        await prefs.setBool(_authKey, true);
        return true;
      }
    } catch (e) {
      debugPrint('Authentication error: $e');
    }
    return false;
  }

  static Future<bool> isBiometricAuthenticated() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      return prefs.getBool(_authKey) ?? false;
    } catch (e) {
      debugPrint('Error reading preferences: $e');
      return false;
    }
  }

  static Future<void> clearAuthentication() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setBool(_authKey, false);
    } catch (e) {
      debugPrint('Error clearing preferences: $e');
    }
  }

  static Future<bool> authenticateWithFallback(BuildContext context) async {
    bool isAuthenticated = await isBiometricAuthenticated();
    
    if (isAuthenticated) {
      return true;
    }

    isAuthenticated = await authenticate();
    
    if (!isAuthenticated) {
      // Fallback to password authentication
      return await _showPasswordDialog(context);
    }
    
    return isAuthenticated;
  }

  static Future<bool> _showPasswordDialog(BuildContext context) async {
    String? password;
    bool isValid = false;
    
    await showDialog(
      context: context,
      barrierDismissible: false,
      builder: (BuildContext context) {
        return AlertDialog(
          title: const Text('Enter Password'),
          content: TextField(
            obscureText: true,
            onChanged: (value) {
              password = value;
            },
            onSubmitted: (value) {
              isValid = value.length >= 6;
              if (isValid) {
                Navigator.of(context).pop(true);
              }
            },
          ),
          actions: <Widget>[
            TextButton(
              child: const Text('Cancel'),
              onPressed: () {
                Navigator.of(context).pop(false);
              },
            ),
            TextButton(
              child: const Text('Submit'),
              onPressed: () {
                if (password != null && password!.length >= 6) {
                  isValid = true;
                  Navigator.of(context).pop(true);
                }
              },
            ),
          ],
        );
      },
    );
    
    return isValid;
  }
}

class AuthenticatedApp extends StatelessWidget {
  final Widget child;
  
  const AuthenticatedApp({Key? key, required this.child}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return FutureBuilder<bool>(
      future: BiometricAuth.isBiometricAuthenticated(),
      builder: (context, snapshot) {
        if (snapshot.connectionState == ConnectionState.waiting) {
          return const Scaffold(
            body: Center(child: CircularProgressIndicator()),
          );
        }
        
        if (snapshot.hasData && snapshot.data!) {
          return child;
        }
        
        return const LoginScreen();
      },
    );
  }
}

